        <div className={`p-4 border-t flex flex-col items-center gap-3 ${isDarkMode ? 'border-slate-700 bg-slate-800/50' : 'border-slate-100 bg-slate-50/50'} ${!isContentVisible ? 'pb-8' : ''}`}>
