              <div className="flex items-center gap-4 sm:gap-6 shrink-0">
                 {activeTab === 'orders' && (
                   <div className="flex items-center gap-2 sm:gap-3 bg-slate-50/80 p-1.5 rounded-xl border border-slate-200">
