                     </button>
                     <span className={`text-[9px] sm:text-[10px] font-black tracking-widest uppercase transition-colors ${viewType === 'post' ? 'text-indigo-600' : 'text-slate-400'}`}>出荷済</span>
                   </div>
                 )}

                 {activeTab === 'calendar' && (
                   <button 
