export default App;

import React, { useState, useMemo } from 'react';
import { Order, Customer, Product } from '../types';
import { ChevronLeft, ChevronRight, X, Info, ChevronRight as ChevronIcon } from 'lucide-react';
import { format, startOfMonth, endOfMonth, eachDayOfInterval, isSameDay, addMonths, subMonths } from 'date-fns';
import { ja } from 'date-fns/locale';

interface Props {
  orders: Order[];
  customers: Customer[];
  products: Product[];
  onEditOrder: (order: Order) => void;
}

const OrderCalendar: React.FC<Props> = ({ orders, customers, products, onEditOrder }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDay, setSelectedDay] = useState<Date | null>(null);

  const days = useMemo(() => {
    const start = startOfMonth(currentDate);
    const end = endOfMonth(currentDate);
    return eachDayOfInterval({ start, end });
  }, [currentDate]);

  const handlePrevMonth = () => setCurrentDate(subMonths(currentDate, 1));
  const handleNextMonth = () => setCurrentDate(addMonths(currentDate, 1));

  const startPadding = startOfMonth(currentDate).getDay();

  // カレンダーの表示基準を出荷日に変更
  const selectedDayOrders = useMemo(() => {
    if (!selectedDay) return [];
    return orders.filter(o => isSameDay(new Date(o.shippingDate), selectedDay));
  }, [selectedDay, orders]);

  return (
    <div className="bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden flex flex-col h-[calc(100vh-180px)]">
      <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-white shrink-0">
        <div className="flex items-center gap-6">
          <h3 className="text-2xl font-black text-slate-800 tracking-tight">
            {format(currentDate, 'yyyy年 MMMM', { locale: ja })}
          </h3>
          <div className="flex gap-2 bg-slate-50 p-1 rounded-xl">
            <button onClick={handlePrevMonth} className="p-2 hover:bg-white hover:shadow-sm rounded-lg transition-all text-slate-500 hover:text-indigo-600">
              <ChevronLeft className="w-6 h-6" />
            </button>
            <button onClick={handleNextMonth} className="p-2 hover:bg-white hover:shadow-sm rounded-lg transition-all text-slate-500 hover:text-indigo-600">
              <ChevronRight className="w-6 h-6" />
            </button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-7 border-b border-slate-100 bg-slate-50 shrink-0">
        {['日', '月', '火', '水', '木', '金', '土'].map((d, i) => (
          <div key={d} className={`px-2 py-3 text-center text-xs font-black tracking-widest uppercase ${i === 0 ? 'text-red-400' : i === 6 ? 'text-indigo-400' : 'text-slate-400'}`}>
            {d}
          </div>
        ))}
      </div>

      <div className="grid grid-cols-7 flex-1 bg-slate-50 gap-px overflow-hidden">
        {Array.from({ length: startPadding }).map((_, i) => (
          <div key={`empty-${i}`} className="bg-slate-50/50 min-h-0"></div>
        ))}

        {days.map(day => {
          // 出荷日基準で集計
          const dayOrders = orders.filter(o => isSameDay(new Date(o.shippingDate), day));
          const isToday = isSameDay(day, new Date());

          return (
            <button 
              key={day.toISOString()} 
              onClick={() => setSelectedDay(day)}
              className="bg-white min-h-0 p-2 flex flex-col text-left group hover:bg-indigo-50 transition-all focus:outline-none"
            >
              <div className="flex justify-between items-center mb-1">
                <span className={`text-sm font-bold flex items-center justify-center w-7 h-7 rounded-lg transition-colors ${
                  isToday ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-500 group-hover:text-indigo-600'
                }`}>
                  {format(day, 'd')}
                </span>
                {dayOrders.length > 0 && (
                  <span className="text-[10px] bg-emerald-50 text-emerald-600 px-1.5 py-0.5 rounded-md font-black ring-1 ring-emerald-100">
                    {dayOrders.length}件
                  </span>
                )}
              </div>

              <div className="flex-1 overflow-hidden space-y-1 pr-0.5">
                {dayOrders.slice(0, 3).map(order => {
                  const customer = customers.find(c => c.id === order.customerId);
                  return (
                    <div 
                      key={order.id} 
                      className="text-[9px] p-1 rounded-md border border-indigo-50 bg-indigo-50/50 text-indigo-900 leading-tight truncate font-bold"
                    >
                      {customer?.company || customer?.name || '不明'}
                    </div>
                  );
                })}
                {dayOrders.length > 3 && (
                  <div className="text-[8px] text-slate-400 font-bold pl-1 italic">+ {dayOrders.length - 3} 件</div>
                )}
              </div>
            </button>
          );
        })}

        {Array.from({ length: Math.ceil((startPadding + days.length) / 7) * 7 - (startPadding + days.length) }).map((_, i) => (
          <div key={`trailing-${i}`} className="bg-slate-50/50 min-h-0"></div>
        ))}
      </div>

      {selectedDay && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-50 p-4 overflow-y-auto">
          <div className="bg-white rounded-[32px] w-full max-w-lg shadow-2xl overflow-hidden animate-in zoom-in duration-300 my-auto">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
              <div className="flex items-center gap-3">
                <div className="p-2.5 bg-indigo-600 rounded-2xl text-white shadow-lg shadow-indigo-100"><Info className="w-5 h-5" /></div>
                <div>
                   <h3 className="text-xl font-black text-slate-800 tracking-tight">
                    {format(selectedDay, 'yyyy年 MMMM d日', { locale: ja })}
                  </h3>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">納品予定リスト (出荷日: {format(selectedDay, 'MM/dd')})</p>
                </div>
              </div>
              <button onClick={() => setSelectedDay(null)} className="w-10 h-10 flex items-center justify-center rounded-full hover:bg-slate-200 text-slate-400 transition-colors"><X className="w-5 h-5" /></button>
            </div>

            <div className="p-6 max-h-[60vh] overflow-y-auto custom-scrollbar space-y-4">
              {selectedDayOrders.length === 0 ? (
                <div className="text-center py-12 text-slate-400 italic font-bold">この日の出荷予定はありません</div>
              ) : (
                selectedDayOrders.map(order => {
                  const customer = customers.find(c => c.id === order.customerId);
                  return (
                    <button 
                      key={order.id} 
                      onClick={() => onEditOrder(order)}
                      className="w-full text-left bg-slate-50 p-4 rounded-2xl border border-slate-100 space-y-3 transition-all hover:bg-white hover:border-indigo-300 hover:shadow-md group/card"
                    >
                      <div className="flex justify-between items-start">
                        <div className="flex-1 min-w-0 pr-4">
                          <div className="font-black text-slate-900 leading-none group-hover/card:text-indigo-600 transition-colors">{customer?.company}</div>
                          <div className="text-xs font-bold text-slate-400 mt-1">{customer?.name} 様</div>
                        </div>
                        <div className="text-right shrink-0">
                          <div className="text-xs font-black text-indigo-600">¥{order.totalAmount.toLocaleString()}</div>
                          <div className={`text-[9px] font-bold px-1.5 py-0.5 rounded mt-1 inline-block ${order.status === 'Shipped' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-200 text-slate-500'}`}>
                            {order.status === 'Shipped' ? '出荷済' : '未出荷'}
                          </div>
                        </div>
                      </div>
                      <div className="pt-3 border-t border-slate-200/50 space-y-1">
                        {order.items.map((item, idx) => (
                          <div key={idx} className="flex justify-between text-[11px] font-bold text-slate-600">
                            <span className="truncate pr-4">{products.find(p => p.id === item.productId)?.name}</span>
                            <span className="shrink-0">x {item.quantity}</span>
                          </div>
                        ))}
                      </div>
                      <div className="pt-2 flex items-center justify-end gap-1 text-[10px] font-black text-indigo-500 opacity-0 group-hover/card:opacity-100 transition-opacity">
                        詳細・編集 <ChevronIcon className="w-3 h-3" />
                      </div>
                    </button>
                  );
                })
              )}
            </div>

            <div className="p-6 bg-slate-50/50 border-t border-slate-100">
              <button 
                onClick={() => setSelectedDay(null)}
                className="w-full py-3.5 bg-slate-900 text-white rounded-2xl font-black text-sm hover:bg-slate-800 transition-all active:scale-95 shadow-xl shadow-slate-200"
              >
                閉じる
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default OrderCalendar;

import React, { useState, useEffect } from 'react';
import { 
  Users, 
  Package, 
  ShoppingCart, 
  Calendar as CalendarIcon, 
  LayoutDashboard, 
  FileSpreadsheet, 
  Download,
  Settings,
  BrainCircuit,
  ChevronRight,
  Moon,
  Sun,
  Globe,
  LogOut,
  X,
  Loader2,
  CheckCircle,
  Mail,
  Hash
} from 'lucide-react';
import { Customer, Product, Order } from './types';
import { INITIAL_CUSTOMERS, INITIAL_PRODUCTS, INITIAL_ORDERS } from './constants';
import Dashboard from './components/Dashboard';
import CustomerManager from './components/CustomerManager';
import ProductManager from './components/ProductManager';
import OrderManager from './components/OrderManager';
import OrderCalendar from './components/OrderCalendar';
import GeminiInsights from './components/GeminiInsights';
import OrderEditModal from './components/OrderEditModal';
import * as XLSX from 'xlsx';

const APP_VERSION = "Ver.1.29";
const COMPANY_NAME = "裏白本舗";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'orders' | 'products' | 'customers' | 'calendar' | 'dashboard' | 'insights'>('orders');
  const [viewType, setViewType] = useState<'pre' | 'post'>('pre');
  const [isContentVisible, setIsContentVisible] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncDone, setSyncDone] = useState(false);

  // Googleカレンダー設定用のステート
  const [googleAccount, setGoogleAccount] = useState(() => {
    return localStorage.getItem('googleAccount') || 'example@gmail.com';
  });
  const [googleCalendarId, setGoogleCalendarId] = useState(() => {
    return localStorage.getItem('googleCalendarId') || '出荷用';
  });
  const [isGoogleLinked, setIsGoogleLinked] = useState(() => {
    const saved = localStorage.getItem('isGoogleLinked');
    return saved !== null ? JSON.parse(saved) : true;
  });

  // 注文編集用グローバルステート
  const [isOrderModalOpen, setIsOrderModalOpen] = useState(false);
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);

  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('customers');
    return saved ? JSON.parse(saved) : INITIAL_CUSTOMERS;
  });
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });
  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('orders');
    return saved ? JSON.parse(saved) : INITIAL_ORDERS;
  });

  useEffect(() => {
    localStorage.setItem('customers', JSON.stringify(customers));
  }, [customers]);

  useEffect(() => {
    localStorage.setItem('products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('orders', JSON.stringify(orders));
  }, [orders]);

  // 設定の永続化
  useEffect(() => {
    localStorage.setItem('googleAccount', googleAccount);
    localStorage.setItem('googleCalendarId', googleCalendarId);
    localStorage.setItem('isGoogleLinked', JSON.stringify(isGoogleLinked));
  }, [googleAccount, googleCalendarId, isGoogleLinked]);

  const handleSync = () => {
    setIsSyncing(true);
    setSyncDone(false);
    setTimeout(() => {
      setIsSyncing(false);
      setSyncDone(true);
      setTimeout(() => setSyncDone(false), 3000);
    }, 2000);
  };

  const openOrderModal = (order: Order | null) => {
    setSelectedOrder(order);
    setIsOrderModalOpen(true);
  };

  const handleSaveOrder = (newOrder: Order) => {
    const oldOrder = selectedOrder;
    // ステータスが「未出荷」から「出荷済」になった場合、在庫を減らす
    const isTransitioningToShipped = newOrder.status === 'Shipped' && (!oldOrder || oldOrder.status === 'Pending');

    if (isTransitioningToShipped) {
      setProducts(prev => prev.map(p => {
        const item = newOrder.items.find(i => i.productId === p.id);
        return item ? { ...p, stock: p.stock - item.quantity } : p;
      }));
    }

    if (selectedOrder) {
      setOrders(prev => prev.map(o => o.id === selectedOrder.id ? newOrder : o));
    } else {
      setOrders(prev => [newOrder, ...prev]);
    }
    setIsOrderModalOpen(false);
  };

  const handleShipOrder = (orderId: string) => {
    const order = orders.find(o => o.id === orderId);
    if (!order || order.status === 'Shipped') return;

    // 在庫減算
    setProducts(prev => prev.map(p => {
      const item = order.items.find(i => i.productId === p.id);
      return item ? { ...p, stock: p.stock - item.quantity } : p;
    }));

    // ステータス更新
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: 'Shipped' } : o));
  };

  const handleDeleteOrder = (orderId: string) => {
    setOrders(prev => prev.filter(o => o.id !== orderId));
    setIsOrderModalOpen(false);
  };

  const exportToExcel = () => {
    const wb = XLSX.utils.book_new();
    const ordersData = orders.map(o => ({
      '注文ID': o.id,
      '顧客名': customers.find(c => c.id === o.customerId)?.name || '不明',
      '会社名': customers.find(c => c.id === o.customerId)?.company || '不明',
      '商品名': products.find(p => p.id === o.productId)?.name || '不明',
      '数量': o.items.reduce((sum, item) => sum + item.quantity, 0),
      '合計金額': o.totalAmount,
      '注文日': o.orderDate,
      '出荷日': o.shippingDate,
      '納品日': o.deliveryDate,
      'ステータス': o.status
    }));
    const wsOrders = XLSX.utils.json_to_sheet(ordersData);
    XLSX.utils.book_append_sheet(wb, wsOrders, '注文一覧');

    const customersData = customers.map(c => ({
      '名前': c.name,
      '会社名': c.company,
      'メール': c.email,
      '電話番号': c.phone,
      'FAX番号': c.fax,
      '郵便番号': c.zipCode || '',
      '住所': c.address,
      '備考': c.notes || ''
    }));
    const wsCustomers = XLSX.utils.json_to_sheet(customersData);
    XLSX.utils.book_append_sheet(wb, wsCustomers, '顧客一覧');

    XLSX.writeFile(wb, `${COMPANY_NAME}_Export_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const navItems = [
    { id: 'orders', label: '注文管理', icon: ShoppingCart },
    { id: 'calendar', label: 'カレンダー', icon: CalendarIcon },
    { id: 'products', label: '商品管理', icon: Package },
    { id: 'customers', label: '顧客管理', icon: Users },
    { id: 'dashboard', label: 'ダッシュボード', icon: LayoutDashboard },
    { id: 'insights', label: 'AI分析', icon: BrainCircuit },
  ] as const;

  const handleNavClick = (id: typeof activeTab) => {
    setActiveTab(id);
    setIsContentVisible(true);
  };

  const toggleSidebar = (e: React.MouseEvent) => {
    if ((e.target as HTMLElement).closest('button')) return;
    if (isContentVisible) {
      setIsContentVisible(false);
    }
  };

  return (
    <div className={`flex h-screen overflow-hidden font-sans transition-colors duration-300 ${isDarkMode ? 'bg-slate-900 text-slate-100' : 'bg-slate-950 text-slate-900'}`}>
      <aside 
        onClick={toggleSidebar}
        className={`border-r flex flex-col shadow-2xl z-20 transition-all duration-500 ease-in-out cursor-pointer relative shrink-0 ${
          isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200'
        } ${
          isContentVisible ? 'w-[15%]' : 'w-[99%]'
        }`}
      >
        <div className={`flex items-center transition-all duration-500 ${isContentVisible ? 'justify-center py-4 px-2' : 'justify-start p-6 mb-2 gap-4'}`}>
          <div className="w-11 h-11 bg-indigo-600 rounded-xl flex items-center justify-center shrink-0 shadow-lg shadow-indigo-100/20">
            <FileSpreadsheet className="text-white w-6 h-6" />
          </div>
          {!isContentVisible && (
            <div className="flex-1 flex items-center justify-between animate-in fade-in slide-in-from-left-4 duration-700 min-w-0">
              <div className="min-w-0">
                <h1 className={`text-3xl font-black tracking-tight whitespace-nowrap overflow-hidden text-ellipsis ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>注文管理システム</h1>
                <p className="text-sm text-indigo-400 font-bold tracking-widest uppercase">Smart Management</p>
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); setIsSettingsOpen(true); }}
                className={`p-3 rounded-2xl transition-all ml-4 ${isDarkMode ? 'bg-slate-700 text-slate-300 hover:text-white' : 'bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50'}`}
              >
                <Settings className="w-8 h-8" />
              </button>
            </div>
          )}
        </div>

        <nav className={`flex-1 flex flex-col overflow-y-auto custom-scrollbar ${isContentVisible ? 'mt-2 px-1 space-y-2 items-center' : 'justify-center max-w-2xl mx-auto w-full px-6 space-y-1.5 pb-6'}`}>
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => handleNavClick(item.id)}
              className={`group w-full flex items-center rounded-xl transition-all duration-300 ${
                isContentVisible 
                ? `justify-center w-11 h-11 ${activeTab === item.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100/20' : isDarkMode ? 'text-slate-400 hover:bg-slate-700' : 'text-slate-500 hover:bg-slate-50'}` 
                : `px-8 py-3.5 text-2xl font-bold bg-slate-50 text-slate-700 hover:bg-indigo-50 hover:text-indigo-700 hover:scale-[1.01] border border-transparent hover:border-indigo-100 shadow-sm ${isDarkMode ? 'bg-slate-700 text-slate-100 hover:bg-slate-600' : ''}`
              }`}
            >
              <div className={`flex items-center justify-center shrink-0 ${isContentVisible ? 'w-full h-full' : 'w-12 h-12'}`}>
                <item.icon className={`transition-transform group-hover:scale-110 ${isContentVisible ? 'w-5 h-5' : 'w-10 h-10'}`} />
              </div>
              {!isContentVisible && (
                <>
                  <span className="truncate flex-1 text-left whitespace-nowrap ml-1 text-2xl font-black">{item.label}</span>
                  <ChevronRight className="w-8 h-8 opacity-20 group-hover:opacity-100 group-hover:translate-x-2 transition-all" />
                </>
              )}
            </button>
          ))}
        </nav>

        <div className={`p-4 border-t flex flex-col items-center gap-3 ${isDarkMode ? 'border-slate-700 bg-slate-800/50' : 'border-slate-100 bg-slate-50/50'} ${!isContentVisible ? 'pb-8' : ''}`}>
          {!isContentVisible ? (
