            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <label className="text-xs font-black text-slate-400 uppercase tracking-widest">注文商品リスト (最大10件)</label>
                {tempItems.length < 10 && (
                  <button type="button" onClick={addItem} className="text-[10px] sm:text-xs font-black text-white bg-indigo-600 px-4 py-2 sm:px-5 sm:py-2.5 rounded-xl hover:bg-indigo-700 shadow-md transition-all active:scale-95">+ 商品を追加</button>
                )}
              </div>
              <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar pr-1">
                {tempItems.map((item, idx) => (
                  <div key={idx} className="flex gap-2 sm:gap-3 items-end bg-slate-50 p-4 sm:p-5 rounded-2xl sm:rounded-3xl border border-slate-100 relative group/row transition-all hover:bg-white hover:shadow-md">
                    <div className="flex-[4] min-w-0">
                      <label className="block text-[8px] sm:text-[9px] font-black text-slate-400 mb-1.5 uppercase tracking-wider">商品名</label>
                      <select 
                        value={item.productId} 
                        onChange={(e) => updateItem(idx, 'productId', e.target.value)}
                        onKeyDown={handleKeyDown}
                        className={`w-full px-2 sm:px-3 py-2 sm:py-2.5 bg-white border rounded-xl text-xs sm:text-sm font-bold focus:ring-2 focus:ring-indigo-500 outline-none transition-colors text-slate-900 ${errors.some(e => e.includes(`${idx + 1}行目の商品名`)) ? 'border-red-300' : 'border-slate-200'}`}
                      >
                        <option value="">選択</option>
                        {products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                      </select>
                    </div>
                    <div className="w-16 sm:w-24">
                      <label className="block text-[8px] sm:text-[9px] font-black text-slate-400 mb-1.5 uppercase tracking-wider">単価</label>
                      <input 
                        type="number" 
                        value={item.unitPrice} 
                        onChange={(e) => updateItem(idx, 'unitPrice', e.target.value)}
                        onKeyDown={handleKeyDown}
                        className="w-full px-2 py-2 sm:py-2.5 bg-white border border-slate-200 rounded-xl text-xs sm:text-sm font-bold outline-none text-slate-900" 
                        placeholder="0"
                      />
                    </div>
                    <div className="w-12 sm:w-16">
                      <label className="block text-[8px] sm:text-[9px] font-black text-slate-400 mb-1.5 uppercase tracking-wider">数量</label>
                      <input 
                        type="number" 
                        value={item.quantity} 
                        onChange={(e) => updateItem(idx, 'quantity', e.target.value)}
                        onKeyDown={handleKeyDown}
                        className={`w-full px-2 py-2 sm:py-2.5 bg-white border rounded-xl text-xs sm:text-sm font-bold outline-none transition-colors text-slate-900 ${errors.some(e => e.includes(`${idx + 1}行目の数量`)) ? 'border-red-300' : 'border-slate-200'}`} 
                        placeholder="0"
                      />
                    </div>
                    {tempItems.length > 1 && (
                      <button type="button" onClick={() => removeItem(idx)} className="text-red-400 hover:text-red-600 pb-2 sm:pb-2.5 flex-shrink-0 transition-all active:scale-90"><MinusCircle className="w-5 h-5 sm:w-6 sm:h-6" /></button>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4 sm:gap-6">
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-3">出荷日</label>
                <input 
                  name="shippingDate" 
                  type="date" 
                  onKeyDown={handleKeyDown}
                  defaultValue={editingOrder?.shippingDate || new Date().toISOString().split('T')[0]} 
                  required 
                  className="w-full px-4 sm:px-5 py-3 sm:py-4 bg-slate-50 border border-slate-100 rounded-2xl text-sm sm:text-base font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all hover:bg-slate-100 text-slate-900" 
                />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-3">納品日</label>
                <input 
                  name="deliveryDate" 
                  type="date" 
                  onKeyDown={handleKeyDown}
                  defaultValue={editingOrder?.deliveryDate || new Date().toISOString().split('T')[0]} 
                  required 
                  className="w-full px-4 sm:px-5 py-3 sm:py-4 bg-slate-50 border border-slate-100 rounded-2xl text-sm sm:text-base font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all hover:bg-slate-100 text-slate-900" 
                />
              </div>
            </div>

            <div className="pt-2">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-4">配送ステータス</label>
              <div className="flex items-center gap-3 sm:gap-4 bg-slate-50 p-1.5 sm:p-2 rounded-2xl w-fit border border-slate-100">
                <button 
                  type="button"
                  onClick={() => setStatus('Pending')}
                  className={`px-6 sm:px-8 py-2.5 sm:py-3 rounded-xl text-xs sm:text-sm font-black transition-all ${status === 'Pending' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  未出荷
                </button>
                <button 
                  type="button"
                  onClick={() => setStatus('Shipped')}
                  className={`px-6 sm:px-8 py-2.5 sm:py-3 rounded-xl text-xs sm:text-sm font-black transition-all flex items-center gap-2 ${status === 'Shipped' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  {status === 'Shipped' && <CheckCircle2 className="w-4 h-4" />}
                  出荷済
                </button>
              </div>
            </div>
          </div>

          <div className="pt-4 space-y-6">
            {errors.length > 0 && (
              <div className="bg-red-50 border border-red-100 rounded-2xl p-4 sm:p-5 animate-in fade-in slide-in-from-top-2 duration-300">
                <div className="flex items-center gap-2 text-red-600 font-black text-xs sm:text-sm mb-3">
                  <AlertTriangle className="w-4 h-4 sm:w-5 sm:h-5" /> 保存できません：以下の項目を修正してください
                </div>
                <ul className="text-[10px] sm:text-xs text-red-500 font-bold list-disc list-inside space-y-1 sm:space-y-1.5 ml-1">
                  {errors.map((err, i) => <li key={i}>{err}</li>)}
                </ul>
              </div>
            )}

            <div className="flex gap-4 sm:gap-6">
              <button type="button" onClick={onClose} className="flex-1 px-4 sm:px-8 py-4 sm:py-5 border-2 border-slate-100 rounded-[20px] sm:rounded-[24px] text-sm sm:text-base font-black text-slate-500 hover:bg-slate-50 transition-all">キャンセル</button>
              <button 
                type="submit" 
                className="flex-1 px-4 sm:px-8 py-4 sm:py-5 rounded-[20px] sm:rounded-[24px] text-sm sm:text-base font-black shadow-xl transition-all active:scale-95 bg-indigo-600 text-white shadow-indigo-200 hover:bg-indigo-700"
              >
                保存する
              </button>
            </div>

            {editingOrder && (
              <button type="button" onClick={() => setIsDeleteConfirmOpen(true)} className="w-full py-2 text-red-400 hover:text-red-600 font-bold text-xs sm:text-sm flex items-center justify-center gap-2 transition-colors">
                <Trash2 className="w-4 h-4" /> この注文を完全に削除する
              </button>
            )}
          </div>
        </form>
      </div>

      {isDeleteConfirmOpen && (
        <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-md flex items-center justify-center z-[110] p-4">
          <div className="bg-white rounded-[32px] w-full max-w-sm shadow-2xl overflow-hidden p-8 sm:p-10 text-center animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 sm:w-20 sm:h-20 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6"><AlertTriangle className="w-8 h-8 sm:w-10 sm:h-10 text-red-500" /></div>
            <h4 className="text-lg sm:text-xl font-black text-slate-900 mb-3">注文を削除しますか？</h4>
            <p className="text-xs text-slate-400 mb-8 leading-relaxed font-bold">この操作は取り消せません。<br/>売上データからも除外されます。</p>
            <div className="flex flex-col gap-3">
              <button onClick={() => onDelete(editingOrder!.id)} className="w-full py-3 sm:py-4 bg-red-600 text-white rounded-2xl font-black text-sm hover:bg-red-700 transition-all shadow-xl active:scale-95">削除を実行する</button>
              <button onClick={() => setIsDeleteConfirmOpen(false)} className="w-full py-3 sm:py-4 bg-slate-100 text-slate-600 rounded-2xl font-bold text-sm hover:bg-slate-200 transition-all">キャンセル</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default OrderEditModal;

import React, { useState, useEffect } from 'react';
import { 
  Users, 
  Package, 
  ShoppingCart, 
  Calendar as CalendarIcon, 
  LayoutDashboard, 
  FileSpreadsheet, 
  Download,
  Settings,
  BrainCircuit,
  ChevronRight,
  Moon,
  Sun,
  Globe,
  LogOut,
  X,
  Loader2,
  CheckCircle,
  Mail,
  Hash
} from 'lucide-react';
import { Customer, Product, Order } from './types';
import { INITIAL_CUSTOMERS, INITIAL_PRODUCTS, INITIAL_ORDERS } from './constants';
import Dashboard from './components/Dashboard';
import CustomerManager from './components/CustomerManager';
import ProductManager from './components/ProductManager';
import OrderManager from './components/OrderManager';
import OrderCalendar from './components/OrderCalendar';
import GeminiInsights from './components/GeminiInsights';
import OrderEditModal from './components/OrderEditModal';
import * as XLSX from 'xlsx';

const APP_VERSION = "Ver.1.31";
const COMPANY_NAME = "裏白本舗";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'orders' | 'products' | 'customers' | 'calendar' | 'dashboard' | 'insights'>('orders');
  const [viewType, setViewType] = useState<'pre' | 'post'>('pre');
  const [isContentVisible, setIsContentVisible] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncDone, setSyncDone] = useState(false);

  // Googleカレンダー設定用のステート
  const [googleAccount, setGoogleAccount] = useState(() => {
    return localStorage.getItem('googleAccount') || 'example@gmail.com';
  });
  const [googleCalendarId, setGoogleCalendarId] = useState(() => {
    return localStorage.getItem('googleCalendarId') || '出荷用';
  });
  const [isGoogleLinked, setIsGoogleLinked] = useState(() => {
    const saved = localStorage.getItem('isGoogleLinked');
    return saved !== null ? JSON.parse(saved) : true;
  });

  // 注文編集用グローバルステート
  const [isOrderModalOpen, setIsOrderModalOpen] = useState(false);
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);

  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('customers');
    return saved ? JSON.parse(saved) : INITIAL_CUSTOMERS;
  });
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });
  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('orders');
    return saved ? JSON.parse(saved) : INITIAL_ORDERS;
  });

  useEffect(() => {
    localStorage.setItem('customers', JSON.stringify(customers));
  }, [customers]);

  useEffect(() => {
    localStorage.setItem('products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('orders', JSON.stringify(orders));
  }, [orders]);

  // 設定の永続化
  useEffect(() => {
    localStorage.setItem('googleAccount', googleAccount);
    localStorage.setItem('googleCalendarId', googleCalendarId);
    localStorage.setItem('isGoogleLinked', JSON.stringify(isGoogleLinked));
  }, [googleAccount, googleCalendarId, isGoogleLinked]);

  const handleSync = () => {
    setIsSyncing(true);
    setSyncDone(false);
    setTimeout(() => {
      setIsSyncing(false);
      setSyncDone(true);
      setTimeout(() => setSyncDone(false), 3000);
    }, 2000);
  };

  const openOrderModal = (order: Order | null) => {
    setSelectedOrder(order);
    setIsOrderModalOpen(true);
  };

  const handleSaveOrder = (newOrder: Order) => {
    const oldOrder = selectedOrder;
    // ステータスが「未出荷」から「出荷済」になった場合、在庫を減らす
    const isTransitioningToShipped = newOrder.status === 'Shipped' && (!oldOrder || oldOrder.status === 'Pending');

    if (isTransitioningToShipped) {
      setProducts(prev => prev.map(p => {
        const item = newOrder.items.find(i => i.productId === p.id);
        return item ? { ...p, stock: p.stock - item.quantity } : p;
      }));
    }

    if (selectedOrder) {
      setOrders(prev => prev.map(o => o.id === selectedOrder.id ? newOrder : o));
    } else {
      setOrders(prev => [newOrder, ...prev]);
    }
    setIsOrderModalOpen(false);
  };

  const handleShipOrder = (orderId: string) => {
    const order = orders.find(o => o.id === orderId);
    if (!order || order.status === 'Shipped') return;

    // 在庫減算
    setProducts(prev => prev.map(p => {
      const item = order.items.find(i => i.productId === p.id);
      return item ? { ...p, stock: p.stock - item.quantity } : p;
    }));

    // ステータス更新
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: 'Shipped' } : o));
  };

  const handleDeleteOrder = (orderId: string) => {
    setOrders(prev => prev.filter(o => o.id !== orderId));
    setIsOrderModalOpen(false);
  };

  const exportToExcel = () => {
    const wb = XLSX.utils.book_new();
    const ordersData = orders.map(o => ({
      '注文ID': o.id,
      '顧客名': customers.find(c => c.id === o.customerId)?.name || '不明',
      '会社名': customers.find(c => c.id === o.customerId)?.company || '不明',
      '商品名': products.find(p => p.id === o.productId)?.name || '不明',
      '数量': o.items.reduce((sum, item) => sum + item.quantity, 0),
      '合計金額': o.totalAmount,
      '注文日': o.orderDate,
      '出荷日': o.shippingDate,
      '納品日': o.deliveryDate,
      'ステータス': o.status
    }));
    const wsOrders = XLSX.utils.json_to_sheet(ordersData);
    XLSX.utils.book_append_sheet(wb, wsOrders, '注文一覧');

    const customersData = customers.map(c => ({
      '名前': c.name,
      '会社名': c.company,
      'メール': c.email,
      '電話番号': c.phone,
      'FAX番号': c.fax,
      '郵便番号': c.zipCode || '',
      '住所': c.address,
      '備考': c.notes || ''
    }));
    const wsCustomers = XLSX.utils.json_to_sheet(customersData);
    XLSX.utils.book_append_sheet(wb, wsCustomers, '顧客一覧');

    XLSX.writeFile(wb, `${COMPANY_NAME}_Export_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const navItems = [
    { id: 'orders', label: '注文管理', icon: ShoppingCart },
    { id: 'calendar', label: 'カレンダー', icon: CalendarIcon },
    { id: 'products', label: '商品管理', icon: Package },
    { id: 'customers', label: '顧客管理', icon: Users },
    { id: 'dashboard', label: 'ダッシュボード', icon: LayoutDashboard },
    { id: 'insights', label: 'AI分析', icon: BrainCircuit },
  ] as const;

  const handleNavClick = (id: typeof activeTab) => {
    setActiveTab(id);
    setIsContentVisible(true);
  };

  const toggleSidebar = (e: React.MouseEvent) => {
    if ((e.target as HTMLElement).closest('button')) return;
    if (isContentVisible) {
      setIsContentVisible(false);
    }
  };

  return (
    <div className={`flex h-screen overflow-hidden font-sans transition-colors duration-300 ${isDarkMode ? 'bg-slate-900 text-slate-100' : 'bg-slate-950 text-slate-900'}`}>
      <aside 
        onClick={toggleSidebar}
        className={`border-r flex flex-col shadow-2xl z-20 transition-all duration-500 ease-in-out cursor-pointer relative shrink-0 ${
          isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200'
        } ${
          isContentVisible ? 'w-[15%]' : 'w-[99%]'
        }`}
      >
        <div className={`flex items-center transition-all duration-500 ${isContentVisible ? 'justify-center py-4 px-2' : 'justify-start p-6 mb-2 gap-4'}`}>
          <div className="w-11 h-11 bg-indigo-600 rounded-xl flex items-center justify-center shrink-0 shadow-lg shadow-indigo-100/20">
            <FileSpreadsheet className="text-white w-6 h-6" />
          </div>
          {!isContentVisible && (
            <div className="flex-1 flex items-center justify-between animate-in fade-in slide-in-from-left-4 duration-700 min-w-0">
              <div className="min-w-0">
                <h1 className={`text-3xl font-black tracking-tight whitespace-nowrap overflow-hidden text-ellipsis ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>注文管理システム</h1>
                <p className="text-sm text-indigo-400 font-bold tracking-widest uppercase">Smart Management</p>
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); setIsSettingsOpen(true); }}
                className={`p-3 rounded-2xl transition-all ml-4 ${isDarkMode ? 'bg-slate-700 text-slate-300 hover:text-white' : 'bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50'}`}
              >
                <Settings className="w-8 h-8" />
              </button>
            </div>
          )}
        </div>

        <nav className={`flex-1 flex flex-col overflow-y-auto custom-scrollbar ${isContentVisible ? 'mt-2 px-1 space-y-2 items-center' : 'justify-center max-w-2xl mx-auto w-full px-6 space-y-1.5 pb-6'}`}>
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => handleNavClick(item.id)}
              className={`group w-full flex items-center rounded-xl transition-all duration-300 ${
                isContentVisible 
                ? `justify-center w-11 h-11 ${activeTab === item.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100/20' : isDarkMode ? 'text-slate-400 hover:bg-slate-700' : 'text-slate-500 hover:bg-slate-50'}` 
                : `px-8 py-3.5 text-2xl font-bold bg-slate-50 text-slate-700 hover:bg-indigo-50 hover:text-indigo-700 hover:scale-[1.01] border border-transparent hover:border-indigo-100 shadow-sm ${isDarkMode ? 'bg-slate-700 text-slate-100 hover:bg-slate-600' : ''}`
              }`}
            >
              <div className={`flex items-center justify-center shrink-0 ${isContentVisible ? 'w-full h-full' : 'w-12 h-12'}`}>
                <item.icon className={`transition-transform group-hover:scale-110 ${isContentVisible ? 'w-5 h-5' : 'w-10 h-10'}`} />
              </div>
              {!isContentVisible && (
                <>
                  <span className="truncate flex-1 text-left whitespace-nowrap ml-1 text-2xl font-black">{item.label}</span>
                  <ChevronRight className="w-8 h-8 opacity-20 group-hover:opacity-100 group-hover:translate-x-2 transition-all" />
                </>
              )}
            </button>
          ))}
        </nav>

        <div className={`p-4 border-t flex flex-col items-center gap-3 ${isDarkMode ? 'border-slate-700 bg-slate-800/50' : 'border-slate-100 bg-slate-50/50'} ${!isContentVisible ? 'pb-8' : ''}`}>
          {!isContentVisible ? (
            <div className="w-full flex items-center justify-start gap-12 overflow-hidden pl-2">
              <span className="text-sm font-black text-slate-300 opacity-60 tracking-widest whitespace-nowrap">{APP_VERSION}</span>
              <button 
                onClick={(e) => { e.stopPropagation(); exportToExcel(); }}
                className="flex-1 max-w-sm flex items-center justify-center gap-3 bg-gradient-to-r from-emerald-600 to-emerald-500 hover:from-emerald-700 hover:to-emerald-600 text-white rounded-2xl transition-all font-bold shadow-lg shadow-emerald-100/10 active:scale-95 py-5 text-xl whitespace-nowrap"
              >
                <Download className="w-6 h-6" />
                Excel出力
              </button>
              <span className="text-sm font-black text-slate-400 opacity-80 tracking-widest whitespace-nowrap">{COMPANY_NAME}</span>
            </div>
          ) : (
            <>
              <button 
                onClick={(e) => { e.stopPropagation(); setIsSettingsOpen(true); }}
