import React, { useState, useMemo } from 'react';
import { Product, Order } from '../types';
import { PackagePlus, Search, Trash2, AlertTriangle, X, ShoppingCart } from 'lucide-react';

interface Props {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  orders: Order[];
}

const ProductManager: React.FC<Props> = ({ products, setProducts, orders }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDeleteConfirmOpen, setIsDeleteConfirmOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  // 未出荷（Pending）の注文から各商品の需要数を計算
  const pendingCounts = useMemo(() => {
    const counts: Record<string, number> = {};
    orders.filter(o => o.status === 'Pending').forEach(order => {
      order.items.forEach(item => {
        counts[item.productId] = (counts[item.productId] || 0) + item.quantity;
      });
    });
    return counts;
  }, [orders]);

  const filteredProducts = products.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const confirmDelete = () => {
    if (editingProduct) {
      setProducts(prev => prev.filter(p => p.id !== editingProduct.id));
      setIsDeleteConfirmOpen(false);
      setIsModalOpen(false);
      setEditingProduct(null);
    }
  };

  const handleSave = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newProduct: Product = {
      id: editingProduct?.id || `p${Date.now()}`,
      name: formData.get('name') as string,
      stock: parseInt(formData.get('stock') as string),
    };

    if (editingProduct) {
      setProducts(prev => prev.map(p => p.id === editingProduct.id ? newProduct : p));
    } else {
      setProducts(prev => [...prev, newProduct]);
    }
    setIsModalOpen(false);
    setEditingProduct(null);
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-col sm:flex-row gap-4 justify-between items-center bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">
        <div className="relative w-full sm:w-96">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input
            type="text"
            placeholder="商品名で検索..."
            className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-100 rounded-xl text-sm outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <button
          onClick={() => { setEditingProduct(null); setIsModalOpen(true); }}
          className="w-full sm:w-auto flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-xl transition-all text-sm font-bold shadow-lg shadow-indigo-100 active:scale-95"
        >
          <PackagePlus className="w-4 h-4" />
          新規商品登録
        </button>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left border-collapse table-fixed">
            <thead>
              <tr className="bg-slate-50/80 text-slate-500 font-bold uppercase text-[10px] tracking-widest border-b border-slate-100">
                <th className="px-6 py-4">商品名称</th>
                <th className="px-6 py-4 w-[110px] text-right leading-tight">
                  注文数<br/><span className="text-[8px] opacity-70">(未出荷)</span>
                </th>
                <th className="px-6 py-4 w-[110px] text-right pr-8">在庫数</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredProducts.length === 0 ? (
                <tr>
                  <td colSpan={3} className="px-6 py-12 text-center text-slate-400 font-medium">登録されている商品はありません</td>
                </tr>
              ) : (
                filteredProducts.map(product => {
                  const pendingCount = pendingCounts[product.id] || 0;
                  return (
                    <tr 
                      key={product.id} 
                      onClick={() => { setEditingProduct(product); setIsModalOpen(true); }}
                      className="hover:bg-indigo-50/50 transition-colors group cursor-pointer"
                    >
                      <td className="px-6 py-5 font-bold text-slate-800 text-base overflow-hidden text-ellipsis whitespace-nowrap">
                        {product.name}
                      </td>
                      <td className="px-6 py-5 text-right">
                        <div className="flex items-center justify-end gap-2">
                          <span className={`inline-block px-3 py-1.5 rounded-lg font-black text-sm text-right ${
                            pendingCount > 0 ? 'bg-indigo-50 text-indigo-600 ring-1 ring-indigo-100' : 'text-slate-300'
                          }`}>
                            {pendingCount.toLocaleString()}
                          </span>
                        </div>
                      </td>
                      <td className="px-6 py-5 text-right pr-8">
                        <span className={`inline-block min-w-[70px] px-3 py-1.5 rounded-lg font-black text-sm text-right ${
                          product.stock <= 0 ? 'bg-red-50 text-red-600 ring-1 ring-red-100' : 
                          product.stock < 10 ? 'bg-amber-50 text-amber-600 ring-1 ring-amber-100' : 
                          'bg-slate-50 text-slate-900 ring-1 ring-slate-100'
                        }`}>
                          {product.stock.toLocaleString()}
                        </span>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
              <h3 className="text-xl font-black text-slate-800 tracking-tight">{editingProduct ? '商品の編集' : '商品の登録'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-slate-200 text-slate-400 transition-colors"><X className="w-5 h-5" /></button>
            </div>
            <form onSubmit={handleSave} className="p-8 space-y-5">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">商品名称</label>
                <input name="name" defaultValue={editingProduct?.name} required className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">現在の在庫数</label>
                <input name="stock" type="number" defaultValue={editingProduct?.stock} required className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all" />
              </div>

              <div className="pt-6 space-y-3">
                <div className="flex gap-4">
                  <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 px-4 py-3 border border-slate-200 rounded-xl text-sm font-bold text-slate-600 hover:bg-slate-50 transition-all">閉じる</button>
                  <button type="submit" className="flex-1 px-4 py-3 bg-indigo-600 text-white rounded-xl text-sm font-bold hover:bg-indigo-700 shadow-lg transition-all active:scale-95">保存する</button>
                </div>
                {editingProduct && (
                  <button 
                    type="button" 
                    onClick={(e) => { e.preventDefault(); setIsDeleteConfirmOpen(true); }}
                    className="w-full flex items-center justify-center gap-2 px-4 py-3 text-red-500 hover:bg-red-50 rounded-xl text-sm font-bold transition-all border border-transparent hover:border-red-100"
                  >
                    <Trash2 className="w-4 h-4" />
                    この商品を削除する
                  </button>
                )}
              </div>
            </form>
          </div>
        </div>
      )}

      {isDeleteConfirmOpen && (
        <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-md flex items-center justify-center z-[60] p-4">
          <div className="bg-white rounded-3xl w-full max-w-sm shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-200">
            <div className="p-8 text-center">
              <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6">
                <AlertTriangle className="w-10 h-10 text-red-500" />
              </div>
              <h4 className="text-xl font-black text-slate-900 mb-2">商品を削除しますか？</h4>
              <p className="text-sm text-slate-500 leading-relaxed mb-8 px-4">
                「{editingProduct?.name}」を削除すると、この商品のデータは元に戻せません。本当によろしいですか？
              </p>
              <div className="flex flex-col gap-3">
                <button 
                  onClick={confirmDelete}
                  className="w-full py-4 bg-red-600 text-white rounded-2xl font-black text-sm hover:bg-red-700 transition-all shadow-xl shadow-red-100 active:scale-95"
                >
                  削除を実行する
                </button>
                <button 
                  onClick={() => setIsDeleteConfirmOpen(false)}
                  className="w-full py-4 bg-slate-100 text-slate-600 rounded-2xl font-bold text-sm hover:bg-slate-200 transition-all"
                >
                  キャンセル
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ProductManager;

import React, { useState, useEffect } from 'react';
import { 
  Users, 
  Package, 
  ShoppingCart, 
  Calendar as CalendarIcon, 
  LayoutDashboard, 
  FileSpreadsheet, 
  Download,
  Settings,
  BrainCircuit,
  ChevronRight,
  Moon,
  Sun,
  Globe,
  LogOut,
  X,
  Loader2,
  CheckCircle,
  Mail,
  Hash
} from 'lucide-react';
import { Customer, Product, Order } from './types';
import { INITIAL_CUSTOMERS, INITIAL_PRODUCTS, INITIAL_ORDERS } from './constants';
import Dashboard from './components/Dashboard';
import CustomerManager from './components/CustomerManager';
import ProductManager from './components/ProductManager';
import OrderManager from './components/OrderManager';
import OrderCalendar from './components/OrderCalendar';
import GeminiInsights from './components/GeminiInsights';
import OrderEditModal from './components/OrderEditModal';
import * as XLSX from 'xlsx';

const APP_VERSION = "Ver.1.33";
const COMPANY_NAME = "裏白本舗";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'orders' | 'products' | 'customers' | 'calendar' | 'dashboard' | 'insights'>('orders');
  const [viewType, setViewType] = useState<'pre' | 'post'>('pre');
  const [isContentVisible, setIsContentVisible] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncDone, setSyncDone] = useState(false);

  // Googleカレンダー設定用のステート
  const [googleAccount, setGoogleAccount] = useState(() => {
    return localStorage.getItem('googleAccount') || 'example@gmail.com';
  });
  const [googleCalendarId, setGoogleCalendarId] = useState(() => {
    return localStorage.getItem('googleCalendarId') || '出荷用';
  });
  const [isGoogleLinked, setIsGoogleLinked] = useState(() => {
    const saved = localStorage.getItem('isGoogleLinked');
    return saved !== null ? JSON.parse(saved) : true;
  });

  // 注文編集用グローバルステート
  const [isOrderModalOpen, setIsOrderModalOpen] = useState(false);
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);

  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('customers');
    return saved ? JSON.parse(saved) : INITIAL_CUSTOMERS;
  });
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });
  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('orders');
    return saved ? JSON.parse(saved) : INITIAL_ORDERS;
  });

  useEffect(() => {
    localStorage.setItem('customers', JSON.stringify(customers));
  }, [customers]);

  useEffect(() => {
    localStorage.setItem('products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('orders', JSON.stringify(orders));
  }, [orders]);

  // 設定の永続化
  useEffect(() => {
    localStorage.setItem('googleAccount', googleAccount);
    localStorage.setItem('googleCalendarId', googleCalendarId);
    localStorage.setItem('isGoogleLinked', JSON.stringify(isGoogleLinked));
  }, [googleAccount, googleCalendarId, isGoogleLinked]);

  const handleSync = () => {
    setIsSyncing(true);
    setSyncDone(false);
    setTimeout(() => {
      setIsSyncing(false);
      setSyncDone(true);
      setTimeout(() => setSyncDone(false), 3000);
    }, 2000);
  };

  const openOrderModal = (order: Order | null) => {
    setSelectedOrder(order);
    setIsOrderModalOpen(true);
  };

  const handleSaveOrder = (newOrder: Order) => {
    const oldOrder = selectedOrder;
    // ステータスが「未出荷」から「出荷済」になった場合、在庫を減らす
    const isTransitioningToShipped = newOrder.status === 'Shipped' && (!oldOrder || oldOrder.status === 'Pending');

    if (isTransitioningToShipped) {
      setProducts(prev => prev.map(p => {
        const item = newOrder.items.find(i => i.productId === p.id);
        return item ? { ...p, stock: p.stock - item.quantity } : p;
      }));
    }

    if (selectedOrder) {
      setOrders(prev => prev.map(o => o.id === selectedOrder.id ? newOrder : o));
    } else {
      setOrders(prev => [newOrder, ...prev]);
    }
    setIsOrderModalOpen(false);
  };

  const handleShipOrder = (orderId: string) => {
    const order = orders.find(o => o.id === orderId);
    if (!order || order.status === 'Shipped') return;

    // 在庫減算
    setProducts(prev => prev.map(p => {
      const item = order.items.find(i => i.productId === p.id);
      return item ? { ...p, stock: p.stock - item.quantity } : p;
    }));

    // ステータス更新
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: 'Shipped' } : o));
  };

  const handleDeleteOrder = (orderId: string) => {
    setOrders(prev => prev.filter(o => o.id !== orderId));
    setIsOrderModalOpen(false);
  };

  const exportToExcel = () => {
    const wb = XLSX.utils.book_new();
    const ordersData = orders.map(o => ({
      '注文ID': o.id,
      '顧客名': customers.find(c => c.id === o.customerId)?.name || '不明',
      '会社名': customers.find(c => c.id === o.customerId)?.company || '不明',
      '商品名': products.find(p => p.id === o.productId)?.name || '不明',
      '数量': o.items.reduce((sum, item) => sum + item.quantity, 0),
      '合計金額': o.totalAmount,
      '注文日': o.orderDate,
      '出荷日': o.shippingDate,
      '納品日': o.deliveryDate,
      'ステータス': o.status
    }));
    const wsOrders = XLSX.utils.json_to_sheet(ordersData);
    XLSX.utils.book_append_sheet(wb, wsOrders, '注文一覧');

    const customersData = customers.map(c => ({
      '名前': c.name,
      '会社名': c.company,
      'メール': c.email,
      '電話番号': c.phone,
      'FAX番号': c.fax,
      '郵便番号': c.zipCode || '',
      '住所': c.address,
      '備考': c.notes || ''
    }));
    const wsCustomers = XLSX.utils.json_to_sheet(customersData);
    XLSX.utils.book_append_sheet(wb, wsCustomers, '顧客一覧');

    XLSX.writeFile(wb, `${COMPANY_NAME}_Export_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const navItems = [
    { id: 'orders', label: '注文管理', icon: ShoppingCart },
    { id: 'calendar', label: 'カレンダー', icon: CalendarIcon },
    { id: 'products', label: '商品管理', icon: Package },
    { id: 'customers', label: '顧客管理', icon: Users },
    { id: 'dashboard', label: 'ダッシュボード', icon: LayoutDashboard },
    { id: 'insights', label: 'AI分析', icon: BrainCircuit },
  ] as const;

  const handleNavClick = (id: typeof activeTab) => {
    setActiveTab(id);
    setIsContentVisible(true);
  };

  const toggleSidebar = (e: React.MouseEvent) => {
    if ((e.target as HTMLElement).closest('button')) return;
    if (isContentVisible) {
      setIsContentVisible(false);
    }
  };

  return (
    <div className={`flex h-screen overflow-hidden font-sans transition-colors duration-300 ${isDarkMode ? 'bg-slate-900 text-slate-100' : 'bg-slate-950 text-slate-900'}`}>
      <aside 
        onClick={toggleSidebar}
        className={`border-r flex flex-col shadow-2xl z-20 transition-all duration-500 ease-in-out cursor-pointer relative shrink-0 ${
          isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200'
        } ${
          isContentVisible ? 'w-[15%]' : 'w-[99%]'
        }`}
      >
        <div className={`flex items-center transition-all duration-500 ${isContentVisible ? 'justify-center py-4 px-2' : 'justify-start p-6 mb-2 gap-4'}`}>
          <div className="w-11 h-11 bg-indigo-600 rounded-xl flex items-center justify-center shrink-0 shadow-lg shadow-indigo-100/20">
            <FileSpreadsheet className="text-white w-6 h-6" />
          </div>
          {!isContentVisible && (
            <div className="flex-1 flex items-center justify-between animate-in fade-in slide-in-from-left-4 duration-700 min-w-0">
              <div className="min-w-0">
                <h1 className={`text-3xl font-black tracking-tight whitespace-nowrap overflow-hidden text-ellipsis ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>注文管理システム</h1>
                <p className="text-sm text-indigo-400 font-bold tracking-widest uppercase">Smart Management</p>
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); setIsSettingsOpen(true); }}
                className={`p-3 rounded-2xl transition-all ml-4 ${isDarkMode ? 'bg-slate-700 text-slate-300 hover:text-white' : 'bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50'}`}
              >
                <Settings className="w-8 h-8" />
              </button>
            </div>
